import * as React from 'react';
import Typography from '@mui/material/Typography';
import Grid from '@mui/material/Grid';
import Card from '@mui/material/Card';
import CardActionArea from '@mui/material/CardActionArea';
import CardContent from '@mui/material/CardContent';
import { Link } from '@mui/material';
import Data from '../../utils/Data';

interface FeaturedPostProps {
  post: {
    url: string;
    date: string;
    description: string;
    image: string;
    imageLabel: string;
    title: string;
  };
}

export default function FeaturedPost(props: FeaturedPostProps) {
  const { post } = props;
  post.image = Data.fetchArticleImage + post.url + ".png"

  return (
    <Grid item xs={12} md={6}>
      <CardActionArea component="a" href={"#/articles/" + post.url}>
        <Card>
          <CardContent sx={{ flex: 1, minHeight: "200px" }}>
            <Typography component="h2" variant="h5">
              {post.title}
            </Typography>
            <Typography variant="subtitle1" sx={{ color: "gray" }}>
              {post.date}
            </Typography>
            <Typography variant="subtitle1" paragraph>
              {post.description}
            </Typography>
            <Link sx={{textDecoration: 'none'}} href={"#/articles/" + post.url} variant="subtitle1" color="primary">
              Czytaj dalej...
            </Link>
          </CardContent>
        </Card>
        <div style={{ border: "1px solid gray", margin: "10px" }}>
        </div>
      </CardActionArea>
    </Grid>
  );
}
