import * as React from 'react';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Markdown from '../../utils/Markdown';

interface ArticleProps {
  post: ReadonlyArray<{ 
    url: string,
    id: string,
    title: string,
    date: string,
    description: string,
    content: string
  }>;
}

export default function MainArticle(props: ArticleProps) {
  const { post } = props;
  let article = post[0];
  let articleData = article.content.replaceAll('<br/>','\n');

  return (
    <Grid item xs={12} md={8} sx={{ paddingTop:"20px", '& .markdown': { py: 3 }}}>
      <Typography variant="h5" sx={{textAlign:"center"}} gutterBottom>
        {article.title}
      </Typography>
      <Typography variant="h6" sx={{textAlign:"center"}} gutterBottom>
        {article.date}
      </Typography>
      <Divider />
      <Markdown className="markdown" key={article.content.substring(0, 40)}>
        {articleData}
      </Markdown>
    </Grid>
  );
}
