import { Box, Container, Grid } from '@mui/material'
import Data from '../utils/Data';
import React, { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'
import Header from '../components/blog/Header';
import Footer from '../components/blog/Footer';
import PoemSidebar from '../components/poems/PoemSidebar';
import '../static/css/Poem.css';
import PoemContent from '../components/poems/PoemContent';

const basePoem = {
  id: '1',
  url: 'poem',
  title: 'Poemat',
  date: 'Autor',
  description: 'Poemat',
  content: ['Trwa ładowanie...'],
  poems: [{title:"Wiersz 1",description:"Opis 1",url:"#"},{title:"Wiersz 2",description:"Opis 2",url:"#"}]
}

const notFoundPoem = {
  id: '-1',
  url: 'undefined',
  date: '',
  description: '404 - Wiersza nie znaleziono',
  content: ['Wiersz o podanym adresie', '404 - Nie istnieje']
}

const Poem = () => {
  let { url } = useParams();
  const [title, setTitle] = useState(basePoem.title)
  const [date, setDate] = useState(basePoem.date)
  const [text, setText] = useState(basePoem.content)

  const [poems, setPoems] = useState(basePoem.poems)

  useEffect(() => {
    const fetchPoems = async () => {
      const res = await fetch(Data.fetchPoem + url + '.json')
      if (res.status === 404) {
        const json = notFoundPoem;
        return json
      }
      const json = await res.json()
      return json
    }
    const getContent = async () => {
      let serverData = await fetchPoems()
      let poem = (serverData as { [key: string]: any })
      setTitle(poem['title'])
      setDate(poem['date'])
      setText(poem['content'])
    }
    getContent()
  }, [url])

  useEffect(() => {
    const getPoems = async () => {
        const serverData = await fetchPoems()
        setPoems(serverData)
    }
    getPoems()
  }, [])

  const fetchPoems = async () => {
    const res = await fetch(Data.fetchPoemList)
    const json = await res.json()
    return json
  }

  return (
    <Container maxWidth="lg">
      <Header title="Rafist0" sections={Data.sections} />
      <Box sx={[{ overflowX: "hidden", marginBlockStart: '20px', alignItems: "center" }]}>
        <Grid container spacing={5} sx={{ mt: 1 }}>
        <PoemContent title={title} date={date} text={text}/>
        <PoemSidebar poems={poems} currentPoem={title}/>
        </Grid>
        <Footer title="Projekt - Wiersze 2022" description="Szczerze i od serca 💖"/>
      </Box>
    </Container>
  )
}

export default Poem